from flask import Flask, request, jsonify
import logging
from logging.handlers import RotatingFileHandler
import json

app = Flask(__name__)

# Configure logging
handler = RotatingFileHandler('app.log', maxBytes=10000, backupCount=1)
formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')
handler.setFormatter(formatter)
app.logger.addHandler(handler)
app.logger.setLevel(logging.INFO)

@app.before_request
def log_request_info():
    app.logger.info(f'Request Headers: {request.headers}')
    app.logger.info(f'Request Body: {request.get_json(silent=True)}')

@app.after_request
def log_response_info(response):
    app.logger.info(f'Response Status: {response.status}')
    app.logger.info(f'Response Data: {response.get_data(as_text=True)}')
    return response

@app.errorhandler(Exception)
def log_exception(error):
    app.logger.error(f'Error: {str(error)}')
    return jsonify({'error': 'Internal Server Error'}), 500

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    user = data.get('username')
    password = data.get('password')
    token = data.get('token')
    
    app.logger.info(f'Login attempt - Username: {user}, Password: {password}, Token: {token}')
    
    # Here you would typically check the credentials
    if user == 'admin' and password == 'secret':
        return jsonify({'message': 'Login successful'}), 200
    else:
        app.logger.warning('Login failed')
        return jsonify({'error': 'Invalid credentials'}), 401

if __name__ == '__main__':
    app.run(debug=True)